#include <stdio.h>

int main(void) {
    int rounds;
    scanf("%d", &rounds);

    int playerScore = 0;
    int computerScore = 0;

    for (int i = 0; i < rounds; i++) {
        int choice, computerChoice;

        printf("Round %d:\n", i + 1);
        printf("Enter your choice (1: Rock, 2: Paper, 3: Scissors): ");
        scanf("%d", &choice);

        if (choice < 1 || choice > 3) {
            printf("Invalid input. Please enter a number between 1 and 3.\n");
            continue;
        }

        computerChoice = rand() % 3 + 1;

        printf("Computer chose: ");
        switch (computerChoice) {
            case 1:
                printf("Rock\n");
                break;
            case 2:
                printf("Paper\n");
                break;
            case 3:
                printf("Scissors\n");
                break;
        }

        if (choice == computerChoice) {
            printf("It's a tie!\n");
        } else if ((choice == 1 && computerChoice == 3) ||
                  (choice == 2 && computerChoice == 1) ||
                  (choice == 3 && computerChoice == 2)) {
            playerScore++;
            printf("You win this round!\n");
        } else {
            computerScore++;
            printf("Computer wins this round!\n");
        }

        printf("Current score: Player %d, Computer %d\n", playerScore, computerScore);
    }

    if (playerScore > computerScore) {
        printf("Congratulations! You win the game.\n");
    } else if (computerScore > playerScore) {
        printf("Computer wins the game. Better luck next time!\n");
    } else {
        printf("It's a tie! The game ends in a draw.\n");
    }

    return 0;
}

