#include <stdio.h>
#include <math.h>

int main(void) {
    double x[4], y[4];
    for (int i = 0; i < 4; i++) scanf("%lf %lf", &x[i], &y[i]);

    // Calculate the lengths of the sides using the distance formula
    double a = sqrt(pow(x[1] - x[0], 2) + pow(y[1] - y[0], 2));
    double b = sqrt(pow(x[2] - x[1], 2) + pow(y[2] - y[1], 2));
    double c = sqrt(pow(x[3] - x[2], 2) + pow(y[3] - y[2], 2));

    // Calculate the semi-perimeter
    double s = (a + b + c) / 2.0;

    // Calculate the area using Heron's formula
    area = sqrt(s * (s - a) * (s - b) * (s - c));

    printf("area %.3f\n", area);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    double sum = 0.0;

    // Read input
    scanf("%d", &n);

    // Compute harmonic-style signed sum
    for (int i = 1; i <= n; i++) {
        sum += pow(-1, i) * i / (2 * i + 1);
    }

    // Print the final sum with a label and 3 decimal places
    printf("result: %.3f\n", sum);

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    double sum = 0.0;

    // Read input from user
    printf("Enter an integer n (1 <= n <= 17): ");
    scanf("%d", &n);

    // Compute the harmonic-style signed sum
    for (int i = 1; i <= n; i++) {
        double term = pow(-1, i) * i / (2 * i + 1);
        sum += term;
    }

    // Print the final sum with a label and 3 decimal places
    printf("result: %.3f\n", sum);

    return 0;
}
